public int minSecondRobotPoints(int[][] grid) {
    int n = grid[0].length;
    for (int r = 0; r < 2; ++r) {
        for (int c = 1; c < n; ++c) {
            grid[r][c] += grid[r][c - 1];
        }
    }
    int[] dp = {grid[0][n - 1], 0};
