        int[] dpNew = {Math.max(dp[0] - grid[0][c], dp[1] + grid[1][c]), Math.max(dp[1] - grid[1][c], dp[0] + grid[0][c])};
        dp[0] = dpNew[0];
        dp[1] = dpNew[1];
    }
    return Math.max(dp[0], dp[1]);
}
